public:
    int findIntegers(int n) {
        int res = 0, a = 1, b = 1;
        for (int i = 0; (1 << i) <= n; ++i) {
            res += a;
            int temp = a;
            a = b;
            b = temp + b;
        }
        return res;
    }
};
